export function getFishByRarity(rarity: GlobalFish['rarity']) {
  return GLOBAL_FISH_DATABASE.filter(f => f.rarity === rarity);
}

export function getFishByType(type: GlobalFish['type']) {
  return GLOBAL_FISH_DATABASE.filter(f => f.type === type);
}

export function getFishByRegion(region: string) {
  return GLOBAL_FISH_DATABASE.filter(f => f.regions.some(r => r.toLowerCase().includes(region.toLowerCase())));
}

export function searchFish(query: string) {
  const q = query.toLowerCase();
  return GLOBAL_FISH_DATABASE.filter(f =>
    f.name.toLowerCase().includes(q) ||
    f.commonName.toLowerCase().includes(q) ||
    f.latinName.toLowerCase().includes(q) ||
    f.regions.some(r => r.toLowerCase().includes(q))
  );
}

export const RARITY_ORDER: GlobalFish['rarity'][] = ['common','uncommon','rare','epic','legendary','mythic'];
